for (const item of $input.all()) {
  const query = item.json.query || {};
  const verifyToken = 'mi_token_secreto_123';
  if (query['hub.verify_token'] === verifyToken) {
    item.json.respuesta = query['hub.challenge'];
  } else {
    item.json.respuesta = 'Token invalido';
  }
}
return $input.all();

const body = $input.first().json.body || $input.first().json;
const entry = body?.entry?.[0];
const changes = entry?.changes?.[0];
const value = changes?.value;
const message = value?.messages?.[0];

if (message && message.type === 'text') {
  const telefono = message.from;
  const phoneNumberId = value.metadata.phone_number_id;
  let history = [];
  let profile = { name: null, email: null };
  let interactionCount = 0;
  try {
    const workflowData = $getWorkflowStaticData('global');
    history = workflowData[`hist_${telefono}`] || [];
    profile = workflowData[`profile_${telefono}`] || { name: null, email: null };
    interactionCount = workflowData[`ic_${telefono}`] || 0;
  } catch(e) {}
  const searchBody = { query: message.text.body, limit: 5 };
  return [{
    json: { telefono, phoneNumberId, mensaje: message.text.body, history, profile, interactionCount, searchBody }
  }];
}
return [{ json: { telefono: null, mensaje: null, skip: true, searchBody: { query: "", limit: 5 } } }];

const openaiResponse = $input.first().json;
const respuestaTexto = openaiResponse.choices?.[0]?.message?.content || 'Lo siento, no pude generar una respuesta.';

return [{
  json: {
    telefono: $('Extraer Mensaje').first().json.telefono,
    phoneNumberId: $('Extraer Mensaje').first().json.phoneNumberId,
    respuesta: respuestaTexto
  }
}];

const extraerData = $('Extraer Mensaje').first().json;
const { telefono, mensaje, phoneNumberId, profile, interactionCount } = extraerData;
const history = extraerData.history || [];

// --- Config del chatbot (inyectada por deploy script) ---
const CONFIG = {
  "identity": {
    "company": "Atrea",
    "description": "un prestigioso despacho de abogados",
    "specialties": [
      "extranjeria",
      "derecho de familia",
      "ley de segunda oportunidad"
    ],
    "channel": "WhatsApp",
    "tone": "profesional, cercano, empatico y elegante"
  },
  "model": {
    "name": "gpt-4o",
    "temperature": 0.7
  },
  "format_rules": [
    "Usa *asterisco simple* para negrita. NUNCA uses **doble asterisco** ni markdown.",
    "Usa _guion bajo_ para cursiva. Listas con guion - o numero 1.",
    "PROHIBIDO: **, ##, backticks, html. Se conciso y claro.",
    "Mensajes cortos: maximo 3-4 parrafos. Evita muros de texto."
  ],
  "capture_tags": {
    "name_tag": "{{NAME:NombreReal}}",
    "email_tag": "{{EMAIL:email@ejemplo.com}}",
    "note": "Si da nombre Y email en un mismo mensaje, pon ambas etiquetas."
  },
  "message_classification": {
    "enabled": true,
    "types": {
      "SALUDO": "hola, buenas, buenos dias, etc.",
      "PREGUNTA_LEGAL": "consulta sobre tramites, derechos, plazos, documentos.",
      "DATOS_PERSONALES": "el usuario da su nombre, email u otro dato.",
      "SEGUIMIENTO": "sigue una conversacion en curso.",
      "OTRO": "cualquier otro caso."
    },
    "note": "No muestres la clasificacion al usuario, usala para adaptar tu respuesta."
  },
  "knowledge_base": {
    "score_threshold": 0.25,
    "intro": "INFORMACION RELEVANTE DE LA BASE DE CONOCIMIENTO:",
    "outro": "Usa esta informacion para responder de forma precisa y profesional. Cita datos concretos (plazos, requisitos, costes) cuando esten disponibles."
  },
  "phases": {
    "no_name": {
      "title": "BIENVENIDA Y CAPTACION DE NOMBRE",
      "objective": "conseguir el nombre del usuario de forma natural y elegante",
      "constraints": [
        "NUNCA le digas que 'necesitas' su nombre ni que es 'obligatorio'. Hazlo fluido y natural.",
        "NUNCA ignores la pregunta del usuario. Siempre responde algo util antes de pedir el nombre.",
        "Si da su nombre, capturalo con {{NAME:Nombre}}."
      ],
      "strategies": [
        {
          "interaction": 0,
          "label": "primera interaccion",
          "instructions": [
            "Dale una bienvenida calida y breve. Presentate como el asistente de {company}.",
            "Menciona brevemente las areas de especialidad ({specialties}).",
            "Preguntale su nombre de forma natural: 'Con quien tengo el gusto de hablar?'",
            "Si el usuario hace una pregunta directa, responde BREVEMENTE pero pregunta su nombre."
          ]
        },
        {
          "interaction": 1,
          "label": "segunda interaccion, aun sin nombre",
          "instructions": [
            "Si hace una pregunta legal, responde con informacion util PERO breve (2-3 lineas max).",
            "Luego: 'Para poder orientarte de forma mas personalizada, me dices tu nombre?'"
          ]
        },
        {
          "interaction": 2,
          "label": "tercera interaccion, sigue sin nombre",
          "instructions": [
            "Enfoque distinto: 'Por cierto, no me has dicho como te llamas. Me gusta poder dirigirme a las personas por su nombre'",
            "Responde con mas detalle, mostrando valor."
          ]
        },
        {
          "interaction": 3,
          "label": "cuarta interaccion, aun sin nombre",
          "instructions": [
            "Tono personal y directo: 'Llevamos un ratito hablando y me encantaria saber tu nombre. Como te llamas?'"
          ]
        }
      ],
      "fallback_strategy": {
        "label_template": "interaccion {n}",
        "instructions": ["Sigue respondiendo con profesionalidad."],
        "ask_pattern": "odd",
        "ask_message": "SI pide el nombre con una frase variada.",
        "skip_message": "NO pidas el nombre, dale un respiro."
      }
    },
    "has_name_no_email": {
      "title": "ATENCION PERSONALIZADA",
      "description": [
        "SIEMPRE usa su nombre para personalizar las respuestas.",
        "Responde con profundidad y profesionalidad usando la base de conocimiento.",
        "En algun momento natural (no en CADA mensaje), preguntale su email para enviarle informacion. Es opcional.",
        "Si ya le preguntaste el email y no respondio, NO insistas mas."
      ],
      "appointment": {
        "title": "OBJETIVO SECUNDARIO: AGENDAR CITA",
        "suggestions": [
          "Si quieres que un especialista revise tu caso, puedo ayudarte a *agendar una cita* con nuestro equipo."
        ],
        "frequency": "Solo cuando la situacion lo amerite o cada 3-4 mensajes.",
        "on_confirm": {
          "steps": [
            "Respondele con entusiasmo.",
            "Pidele su correo electronico para enviarle toda la informacion.",
            "Excelente, {name}! Para enviarte toda la informacion sobre tu consulta y los documentos que necesitaras, me facilitas tu correo electronico?"
          ],
          "on_email_captured": "Perfecto, {name}! Hemos registrado tu correo. Te enviaremos toda la informacion detallada sobre tu consulta, la documentacion necesaria y los proximos pasos. Nuestro equipo se pondra en contacto contigo para confirmar fecha y hora."
        }
      }
    },
    "complete_profile": {
      "title": "CLIENTE IDENTIFICADO",
      "description": [
        "Ya tienes toda la informacion. No pidas mas datos personales.",
        "Ofrece un servicio excepcional usando la base de conocimiento."
      ],
      "appointment": {
        "title": "AGENDAR CITA",
        "instructions": [
          "Sugiere cita cuando el caso sea complejo.",
          "No insistas si ya dijo que no."
        ],
        "on_confirm": "Perfecto, {name}! Te enviaremos a {email} toda la informacion. Nuestro equipo confirmara fecha y hora."
      }
    }
  }
};

// --- Contexto de knowledge base ---
let knowledgeContext = '';
try {
  const searchData = $input.first().json;
  if (searchData?.results?.length > 0) {
    knowledgeContext = '\n' + CONFIG.knowledge_base.intro + '\n';
    for (const result of searchData.results) {
      if (result.score > CONFIG.knowledge_base.score_threshold) {
        knowledgeContext += '\n--- ' + (result.metadata?.title || 'Documento') + ' ---\n';
        knowledgeContext += result.text + '\n';
      }
    }
    knowledgeContext += '\n' + CONFIG.knowledge_base.outro + '\n';
  }
} catch(e) {}

// --- Construir system prompt desde config ---
const id = CONFIG.identity;
const tpl = (s) => s.replace(/\{company\}/g, id.company)
                     .replace(/\{specialties\}/g, id.specialties.join(', '))
                     .replace(/\{name\}/g, profile?.name || '')
                     .replace(/\{email\}/g, profile?.email || '');

let sp = `Eres el asistente virtual de *${id.company}*, ${id.description} especializado en ${id.specialties.join(', ')}. Respondes UNICAMENTE por ${id.channel}. Tu tono es ${id.tone}.\n`;

sp += '\nREGLAS DE FORMATO (obligatorio):\n';
for (const rule of CONFIG.format_rules) sp += '- ' + rule + '\n';

sp += '\nETIQUETAS DE CAPTURA (invisibles para el usuario, siempre al FINAL del mensaje):\n';
sp += '- Cuando el usuario te diga su nombre: ' + CONFIG.capture_tags.name_tag + '\n';
sp += '- Cuando el usuario te diga su email: ' + CONFIG.capture_tags.email_tag + '\n';
sp += '- ' + CONFIG.capture_tags.note + '\n';

if (CONFIG.message_classification.enabled) {
  sp += '\nCLASIFICACION DE MENSAJES:\n';
  sp += 'Antes de responder, clasifica internamente el mensaje del usuario:\n';
  for (const [type, desc] of Object.entries(CONFIG.message_classification.types)) {
    sp += `- ${type}: ${desc}\n`;
  }
  sp += CONFIG.message_classification.note + '\n';
}

const hasName = profile?.name;
const hasEmail = profile?.email;
const ic = interactionCount || 0;

if (!hasName) {
  const phase = CONFIG.phases.no_name;
  sp += `\n=== FASE ACTUAL: ${phase.title} ===\n`;
  sp += `Tu OBJETIVO PRINCIPAL es ${phase.objective}.\n`;
  for (const c of phase.constraints) sp += c + '\n';
  sp += '\n';

  const strategy = phase.strategies.find(s => s.interaction === ic);
  if (strategy) {
    sp += `ESTRATEGIA (${strategy.label}):\n`;
    for (const inst of strategy.instructions) sp += '- ' + tpl(inst) + '\n';
  } else {
    const fb = phase.fallback_strategy;
    sp += `ESTRATEGIA (${fb.label_template.replace('{n}', String(ic + 1))}):\n`;
    for (const inst of fb.instructions) sp += '- ' + inst + '\n';
    const shouldAsk = ic % 2 !== 0;
    sp += '- En ESTA interaccion ' + (shouldAsk ? fb.ask_message : fb.skip_message) + '\n';
  }

} else if (!hasEmail) {
  const phase = CONFIG.phases.has_name_no_email;
  sp += `\n=== FASE ACTUAL: ${phase.title} ===\n`;
  sp += `El usuario se llama *${profile.name}*.\n`;
  for (const d of phase.description) sp += '- ' + d + '\n';

  const apt = phase.appointment;
  sp += `\n=== ${apt.title} ===\n`;
  sp += 'Busca momentos naturales para sugerirle agendar una consulta con los abogados de ' + id.company + '.\n';
  for (const s of apt.suggestions) sp += '- ' + s + '\n';
  sp += '- ' + apt.frequency + '\n';

  sp += '\n=== CUANDO CONFIRMA QUERER CITA ===\n';
  sp += 'Si el usuario dice que SI quiere cita:\n';
  for (const step of apt.on_confirm.steps) sp += '- ' + tpl(step) + '\n';
  sp += '- Cuando de su email, capturalo con {{EMAIL:correo@ejemplo.com}} y responde:\n';
  sp += '  "' + tpl(apt.on_confirm.on_email_captured) + '"\n';

} else {
  const phase = CONFIG.phases.complete_profile;
  sp += `\n=== FASE ACTUAL: ${phase.title} ===\n`;
  sp += `El usuario se llama *${profile.name}* y su email es ${profile.email}.\n`;
  for (const d of phase.description) sp += '- ' + d + '\n';

  const apt = phase.appointment;
  sp += `\n=== ${apt.title} ===\n`;
  for (const inst of apt.instructions) sp += '- ' + inst + '\n';
  sp += '- Si dice que SI: "' + tpl(apt.on_confirm) + '"\n';
}

sp += knowledgeContext;

const messages = [
  { role: "system", content: sp },
  ...history,
  { role: "user", content: mensaje }
];

return [{
  json: {
    telefono, mensaje, phoneNumberId, profile, interactionCount: ic,
    openaiBody: { model: CONFIG.model.name, messages, temperature: CONFIG.model.temperature }
  }
}];

const { telefono, phoneNumberId, respuesta, interactionCount } = $input.first().json;
const mensaje = $('Extraer Mensaje').first().json.mensaje;
const currentProfile = $('Extraer Mensaje').first().json.profile || { name: null, email: null };

const nameMatch = respuesta.match(/\{\{NAME:([^}]+)\}\}/);
const emailTagMatch = respuesta.match(/\{\{EMAIL:([^}]+)\}\}/);
const userEmailMatch = mensaje.match(/[\w.+-]+@[\w.-]+\.[a-zA-Z]{2,}/);

const profile = { ...currentProfile };
if (nameMatch) profile.name = nameMatch[1].trim();
if (emailTagMatch) {
  profile.email = emailTagMatch[1].trim();
} else if (userEmailMatch && !currentProfile.email) {
  profile.email = userEmailMatch[0];
}

const respuestaWA = respuesta
  .replace(/\{\{NAME:[^}]+\}\}/g, '')
  .replace(/\{\{EMAIL:[^}]+\}\}/g, '')
  .replace(/\*\*([^*]+)\*\*/g, '*$1*')
  .replace(/[\u200B\u200C\u200D\u2060\uFEFF\u00AD]/g, '')
  .trim();

let workflowData, key, history;
try {
  workflowData = $getWorkflowStaticData('global');
  key = `hist_${telefono}`;
  history = (workflowData[key] || []).map(msg => ({
    ...msg,
    content: msg.content.replace(/\*\*([^*]+)\*\*/g, '*$1*')
  }));
  history.push({ role: 'user', content: mensaje });
  history.push({ role: 'assistant', content: respuestaWA });
  if (history.length > 20) history.splice(0, history.length - 20);
  workflowData[key] = history;
  workflowData[`profile_${telefono}`] = profile;
  if (nameMatch) {
    workflowData[`ic_${telefono}`] = 0;
  } else if (!currentProfile.name) {
    workflowData[`ic_${telefono}`] = (interactionCount || 0) + 1;
  }
} catch(e) {}

// --- Atlas CRM: preparar datos si email es nuevo ---
const emailJustCaptured = (!!emailTagMatch || (!!userEmailMatch && !currentProfile.email)) && !!profile.name && !!profile.email;
let atlasContactBody = null;
let atlasLeadBody = null;

if (emailJustCaptured) {
  const nameParts = (profile.name || '').split(' ');
  const firstName = nameParts[0] || '';
  const lastName = nameParts.slice(1).join(' ') || '';

  let convNotes = '';
  for (const msg of history.slice(-6)) {
    const prefix = msg.role === 'user' ? 'Usuario' : 'Bot';
    convNotes += prefix + ': ' + msg.content.substring(0, 200) + '\n';
  }

  atlasContactBody = {
    first_name: firstName,
    last_name: lastName,
    email: profile.email,
    phone: '+' + telefono,
    source_detail: 'WhatsApp Bot',
    tags: ['whatsapp', 'consulta-legal'],
    notes: convNotes || 'Contacto capturado desde WhatsApp Bot de Atrea'
  };

  atlasLeadBody = {
    title: 'Consulta Legal - ' + profile.name,
    priority: 'medium',
    currency: 'EUR',
    notes: 'Lead generado desde WhatsApp Bot. ' + (convNotes ? convNotes.substring(0, 500) : '')
  };
}

const waBodyObj = {
  messaging_product: 'whatsapp',
  to: telefono,
  type: 'text',
  text: { body: respuestaWA }
};

return [{ json: {
  telefono, phoneNumberId, respuesta: respuestaWA, waBodyObj, profile,
  emailJustCaptured, atlasContactBody, atlasLeadBody
} }];

const items = $input.all();
const results = [];
for (const item of items) {
  if (item.json.emailJustCaptured && item.json.atlasContactBody) {
    results.push(item);
  }
}
return results;
